// Global stats
struct TestStats {
    uint32_t passed;
    uint32_t failed;
    uint32_t total;
};
static TestStats g_stats = {0, 0, 0};

// Telemetry Driven Wave Simulator
struct WaveSim {
    float phi[WAVE_GRID_SIZE];
    float phi_prev[WAVE_GRID_SIZE];
    float phi_next[WAVE_GRID_SIZE];
    float source_amplitude;
    uint32_t step;
};

void init_wave_sim(WaveSim *sim) {
    std::memset(sim->phi, 0, sizeof(sim->phi));
    std::memset(sim->phi_prev, 0, sizeof(sim->phi_prev));
    std::memset(sim->phi_next, 0, sizeof(sim->phi_next));
    sim->source_amplitude = 0.0f;
    sim->step = 0;
}

void step_wave_sim(WaveSim *sim, float dt) {
    if (dt <= 0.0f) {
        std::cout << "  [WARNING] Telemetry query step bypassed: dt must be positive (Received: " << dt << ")\n";
        return;
    }

    float r2 = WAVE_COURANT * WAVE_COURANT;
    float time = sim->step * dt;
    sim->source_amplitude = std::sin(WAVE_OMEGA * time);

    // Driven Wave Equation: d^2(phi)/dt^2 - v^2 * del^2(phi) = A * sin(omega*t - k*x)
    for (int i = 1; i < WAVE_GRID_SIZE - 1; i++) {
        float laplacian = sim->phi[i + 1] - 2.0f * sim->phi[i] + sim->phi[i - 1];
        
        // Add driving term spatially
        float driving_force = 2.0f * std::sin(WAVE_OMEGA * time - WAVE_K * i);
        sim->phi_next[i] = 2.0f * sim->phi[i] - sim->phi_prev[i] + r2 * laplacian + dt * dt * driving_force;

        if (sim->phi_next[i] != sim->phi_next[i] || sim->phi_next[i] > 1e9f || sim->phi_next[i] < -1e9f) {
            std::cout << "  [CRITICAL] Numerical divergence detected in telemetry wave. Auto-healing state to zero...\n";
            init_wave_sim(sim);
            return;
        }
    }

    // Dirichlet boundary conditions
    sim->phi_next[0] = 0.0f;
    sim->phi_next[WAVE_GRID_SIZE - 1] = 0.0f;

    std::memcpy(sim->phi_prev, sim->phi, sizeof(sim->phi));
    std::memcpy(sim->phi, sim->phi_next, sizeof(sim->phi));

    sim->step++;
}

void print_wave_profile(const WaveSim *sim) {
    const int height = 11;
    const int mid_y = height / 2;
    char display[11][WAVE_GRID_SIZE + 1];

    for (int i = 0; i < height; i++) {
        for (int j = 0; j < WAVE_GRID_SIZE; j++) {
            display[i][j] = (i == mid_y) ? '-' : ' ';
        }
        display[i][WAVE_GRID_SIZE] = '\0';
    }

    for (int i = 0; i < WAVE_GRID_SIZE; i++) {
        float val = sim->phi[i];
        if (val > 1.5f) val = 1.5f;
        if (val < -1.5f) val = -1.5f;

        int y = mid_y - (int)std::round(val * (float)mid_y / 1.5f);
        if (y < 0) y = 0;
        if (y >= height) y = height - 1;

        display[y][i] = (y == mid_y) ? 'o' : '*';
    }

    std::cout << "  [Step " << std::setw(3) << std::setfill('0') << sim->step
              << " | Heartbeat Amp: " << std::showpos << std::fixed << std::setprecision(4)
              << sim->source_amplitude << "]\n";
    std::cout << "  +----------------------------------------+\n";
    for (int i = 0; i < height; i++) {
        std::cout << "  |" << display[i] << "|\n";
    }
    std::cout << "  +----------------------------------------+\n";
}

