    std::cout << "==================================================\n\n";

    std::cout << "[1/2] Running " << NUM_TEST_CASES << " Chaotic Audit Injections...\n";
    run_all_chaos_tests();
    std::cout << "      Assertions Run: " << g_stats.total << "\n";
    std::cout << "      Passed: " << g_stats.passed << " | Failed: " << g_stats.failed << "\n";
    
    if (g_stats.failed == 0) {
        std::cout << "      SUCCESS: All controls verified operational under chaos challenges.\n\n";
    } else {
        std::cout << "      WARNING: Security control bypass vulnerabilities detected!\n\n";
    }

    std::cout << "[2/2] Running Continuous Bypass Injection Wave Simulation...\n";
    std::cout << "      Equation: d^2(phi)/dt^2 - v^2 * del^2(phi) = A * sin(omega*t - k*x)\n\n";

    WaveSim sim;
    init_wave_sim(&sim);

    std::cout << "  --- Telemetry Wave Edge Cases Assertions ---\n";
    step_wave_sim(&sim, 0.0f);
    step_wave_sim(&sim, -0.5f);
